            $(window).trigger('resize');

			// Overlay Fade In
			$( '.wpr-popup-overlay' ).hide().fadeIn();

			// Close Button Show Up Delay
			popup.find( '.wpr-popup-close-btn' ).css( 'opacity', '0' );
